/**
 * Photo format conversion utilities.
 * Data URL ↔ Blob, File → preview URL, cleanup.
 */

/**
 * Convert a base64 data URL to a Blob.
 * @param {string} dataUrl — e.g. "data:image/jpeg;base64,..."
 * @returns {Blob}
 */
export function dataUrlToBlob(dataUrl) {
  if (!dataUrl || !dataUrl.includes(',')) {
    throw new Error('Invalid data URL')
  }
  const [header, data] = dataUrl.split(',')
  const mime = header.match(/:(.*?);/)?.[1] || 'image/jpeg'
  const bytes = atob(data)
  const arr = new Uint8Array(bytes.length)
  for (let i = 0; i < bytes.length; i++) {
    arr[i] = bytes.charCodeAt(i)
  }
  return new Blob([arr], { type: mime })
}

/**
 * Create an object URL for previewing a File/Blob in the UI.
 * Caller MUST call cleanupPreview() or URL.revokeObjectURL() when done.
 * @param {File|Blob} file
 * @returns {string} object URL
 */
export function fileToPreview(file) {
  return URL.createObjectURL(file)
}

/**
 * Revoke a single preview URL to free memory.
 * @param {string} url — object URL from fileToPreview()
 */
export function cleanupPreview(url) {
  if (url && url.startsWith('blob:')) {
    URL.revokeObjectURL(url)
  }
}

/**
 * Revoke an array of preview URLs.
 * @param {string[]} urls
 */
export function cleanupPreviews(urls) {
  if (!Array.isArray(urls)) return
  urls.forEach(cleanupPreview)
}

/**
 * Read a File as a data URL string.
 * @param {File|Blob} file
 * @returns {Promise<string>} data URL
 */
export function fileToDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(reader.result)
    reader.onerror = () => reject(new Error('Failed to read file'))
    reader.readAsDataURL(file)
  })
}
